namespace sv_2615ddc7ffe046ca92eb8651857b7896.Services;

public enum ThemeMode { Light, Dark, System }

public record ThemeInfo(ThemeMode Mode, string AccentColor)
{
    public static ThemeInfo Default => new(ThemeMode.System, "#0d6efd");
}

using Microsoft.AspNetCore.Components;

namespace sv_2615ddc7ffe046ca92eb8651857b7896.Services;

/// <summary>
/// Scoped service (one per circuit) that owns the current theme state
/// and exposes a <see cref="CascadingValueSource{T}"/> so every
/// component — interactive or static-at-first-render — can receive
/// updates via <c>[CascadingParameter]</c>.
/// </summary>
public class ThemeService
{
    private ThemeInfo _current = ThemeInfo.Default;
    private readonly CascadingValueSource<ThemeInfo> _source;

    public ThemeService()
    {
        _source = new CascadingValueSource<ThemeInfo>(() => _current, isFixed: false);
    }

    /// <summary>
    /// Register this with <c>AddCascadingValue</c> in DI so the
    /// framework provides it at the renderer level (works across
    /// render modes without a wrapper component in the tree).
    /// </summary>
    public CascadingValueSource<ThemeInfo> Source => _source;

    public ThemeInfo Current => _current;

    public async Task SetThemeModeAsync(ThemeMode mode)
    {
        _current = _current with { Mode = mode };
        await _source.NotifyChangedAsync();
    }

    public async Task SetAccentColorAsync(string accentColor)
    {
        _current = _current with { AccentColor = accentColor };
        await _source.NotifyChangedAsync();
    }

    public async Task SetAsync(ThemeMode mode, string accentColor)
    {
        _current = new ThemeInfo(mode, accentColor);
        await _source.NotifyChangedAsync();
    }
}

