@rendermode InteractiveServer
@using sv_2615ddc7ffe046ca92eb8651857b7896.Services
@inject ThemeService ThemeService

<span class="theme-indicator badge rounded-pill"
      style="background-color: @Theme?.AccentColor; cursor: pointer;"
      title="Click to toggle theme"
      @onclick="ToggleThemeAsync">
    @ThemeLabel
</span>

@code {
    [CascadingParameter] public ThemeInfo? Theme { get; set; }

    private string ThemeLabel => Theme?.Mode switch
    {
        ThemeMode.Light  => "☀️ Light",
        ThemeMode.Dark   => "🌙 Dark",
        ThemeMode.System => "💻 System",
        _                => "💻 System"
    };

    private async Task ToggleThemeAsync()
    {
        var next = Theme?.Mode switch
        {
            ThemeMode.Light  => ThemeMode.Dark,
            ThemeMode.Dark   => ThemeMode.System,
            ThemeMode.System => ThemeMode.Light,
            _                => ThemeMode.Light
        };
        await ThemeService.SetThemeModeAsync(next);
    }
}

@page "/settings"
@rendermode InteractiveServer
@using sv_2615ddc7ffe046ca92eb8651857b7896.Services
@inject ThemeService ThemeService

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card" style="max-width: 480px;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>

        <div class="mb-3">
            <label class="form-label">Mode</label>
            <div class="btn-group d-flex" role="group">
                @foreach (var mode in Enum.GetValues<ThemeMode>())
                {
                    var isActive = Theme?.Mode == mode;
                    <button type="button"
                            class="btn @(isActive ? "btn-primary" : "btn-outline-primary")"
                            style="@(isActive ? $"background-color:{Theme?.AccentColor};border-color:{Theme?.AccentColor}" : "")"
                            @onclick="() => ThemeService.SetThemeModeAsync(mode)">
                        @mode
                    </button>
                }
            </div>
        </div>

        <div class="mb-3">
            <label class="form-label" for="accentColor">Accent Color</label>
            <input id="accentColor" type="color" class="form-control form-control-color"
                   value="@Theme?.AccentColor"
                   @onchange="OnAccentChanged" />
        </div>

        <div class="mt-4 p-3 rounded"
             style="background-color: @Theme?.AccentColor; color: white;">
            Preview — @Theme?.Mode mode, accent @Theme?.AccentColor
        </div>
    </div>
</div>

@code {
    [CascadingParameter] public ThemeInfo? Theme { get; set; }

    private async Task OnAccentChanged(ChangeEventArgs e)
    {
        if (e.Value is string color && !string.IsNullOrWhiteSpace(color))
        {
            await ThemeService.SetAccentColorAsync(color);
        }
    }
}

